queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?press_conferences a :Press_Conferences .
    ?press_conferences p:topic ?topic .
    ?press_conferences p:person ?person_f .
    FILTER(STR(?person_f) = "Jack Layton")
    BIND(?topic AS ?o0)
  }
  UNION
  {
    ?media_scrums a :Media_Scrums .
    ?media_scrums p:topic ?topic .
    ?media_scrums p:person ?person_f .
    FILTER(STR(?person_f) = "Jack Layton")
    BIND(?topic AS ?o0)
  }
}

